'use client'

import { useState, useEffect } from 'react'

const STORAGE_KEY = 'cookie-consent'

/** Cookie consent banner. Shows once per browser; persists choice to localStorage. */
export default function CookieBanner() {
	const [visible, setVisible] = useState(false)

	useEffect(() => {
		try {
			if (!localStorage.getItem(STORAGE_KEY)) setVisible(true)
		} catch { /* storage blocked — stay hidden */ }
	}, [])

	function grant() {
		try { localStorage.setItem(STORAGE_KEY, 'granted') } catch { /* */ }
		// Update GA4 Consent Mode v2 for the current session if already loaded
		if (typeof (window as Window & { gtag?: (...args: unknown[]) => void }).gtag === 'function') {
			(window as Window & { gtag: (...args: unknown[]) => void }).gtag(
				'consent', 'update', { analytics_storage: 'granted' }
			)
		}
		setVisible(false)
	}

	function deny() {
		try { localStorage.setItem(STORAGE_KEY, 'denied') } catch { /* */ }
		setVisible(false)
	}

	if (!visible) return null

	return (
		<div
			role="dialog"
			aria-label="Cookie consent"
			className="fixed bottom-0 left-0 right-0 z-50 border-t border-white/10 bg-black/90 backdrop-blur-sm px-4 py-3 flex flex-col sm:flex-row items-center gap-3 text-xs"
		>
			<p className="flex-1 opacity-60">
				This site uses Google Analytics to understand how visitors use it. No personal data is shared beyond standard GA4 defaults.
			</p>
			<div className="flex gap-4 shrink-0">
				<button onClick={deny} className="opacity-50 hover:opacity-100 transition-opacity">
					Decline
				</button>
				<button
					onClick={grant}
					className="px-3 py-1.5 rounded bg-white/10 hover:bg-white/20 transition-colors"
				>
					Accept
				</button>
			</div>
		</div>
	)
}
